mapper.delete:
DELETE FROM ai_classroom_portrait_ability
WHERE classroom_id = #{classroomId}
  AND course_id = #{courseId}

mapper.select:
SELECT ability_id as id,
       ability_name as abilityName,
       import_level as importLevel,
       datavalue as dataValue,
       stu_datavalue as stuDataValue
FROM ai_classroom_portrait_ability
WHERE classroom_id = #{classroomId}
  AND course_id = #{courseId}
  AND num = #{num}
